    path: /Users/ryryo/dev/lpto-tanstack
```

### 2. 型定義 `dashboard/lib/types.ts`

```typescript
export type PlanStatus = 'not-started' | 'in-progress' | 'in-review' | 'completed';

export interface TodoItem {
  title: string;
  checked: boolean;
  hasReview: boolean;
  reviewFilled: boolean;
}

export interface Gate {
  id: string;
  title: string;
  todos: TodoItem[];
}

export interface PlanFile {
  filePath: string;
  fileName: string;
  projectName: string;
  title: string;
  status: PlanStatus;
  gates: Gate[];
  todos: TodoItem[];
  progress: {
    total: number;
    completed: number;
    percentage: number;
  };
}

export interface ProjectConfig {
  name: string;
  path: string;
}

export interface ProjectsConfig {
  projects: ProjectConfig[];
}
```

### 3. config.ts 作成

```typescript
import fs from 'fs';
import path from 'path';
import { parse } from 'yaml';
import type { ProjectsConfig } from './types';

export function loadProjectsConfig(): ProjectsConfig {
  const configPath = path.join(process.cwd(), 'projects.yaml');
  const content = fs.readFileSync(configPath, 'utf-8');
  return parse(content) as ProjectsConfig;
}
```

## 検証
- `dashboard/projects.yaml` が正しい YAML としてパースできること
- 型定義にコンパイルエラーがないこと: `cd dashboard && npx tsc --noEmit`

## 手順

TDD でテストファーストで実装する。

### テストケース（RED）

`dashboard/__tests__/project-scanner.test.ts` に以下のテストを記述:

1. **正常系**: 指定パスの `docs/PLAN/` から .md ファイルを収集
2. **PLAN ディレクトリなし**: `docs/PLAN/` が存在しないプロジェクト → 空配列
3. **アクセスエラー**: パスが無効 → エラーをスキップし空配列
4. **ディレクトリモード PLAN**: `docs/PLAN/{slug}/spec.md` 形式も検出
5. **複数プロジェクト統合**: 全プロジェクトの PLAN を統合して返す

### テストセットアップ

テスト用に一時ディレクトリを作成し、テスト用 PLAN ファイルを配置する:
```typescript
import { mkdtempSync, mkdirSync, writeFileSync, rmSync } from 'fs';
import { join } from 'path';
import os from 'os';

let tmpDir: string;
beforeEach(() => {
  tmpDir = mkdtempSync(join(os.tmpdir(), 'scanner-test-'));
});
afterEach(() => {
  rmSync(tmpDir, { recursive: true });
});
```

### 実装（GREEN）

`dashboard/lib/project-scanner.ts`:

```typescript
export function scanProjectPlans(projectPath: string, projectName: string): PlanFile[]
export function scanAllProjects(config: ProjectsConfig): PlanFile[]
```

主要処理:
1. `projectPath/docs/PLAN/` の存在チェック（try-catch）
2. ディレクトリ内の `.md` ファイルを `fs.readdirSync` で列挙
3. サブディレクトリ内の `spec.md` も検出（ディレクトリモード対応）
4. 各ファイルを `parsePlanFile` でパースして返す
5. `scanAllProjects` は全プロジェクトを走査して統合

## 検証
```bash
cd dashboard && npx vitest run __tests__/project-scanner.test.ts
```
全テストが PASS すること。

## 手順

`dashboard/app/api/plans/route.ts` を作成:

```typescript
import { NextResponse } from 'next/server';
import { loadProjectsConfig } from '@/lib/config';
import { scanAllProjects } from '@/lib/project-scanner';

export async function GET() {
  try {
    const config = loadProjectsConfig();
    const plans = scanAllProjects(config);
    return NextResponse.json({
      projects: config.projects,
      plans,
    });
  } catch (error) {
    return NextResponse.json(
      { error: 'Failed to load plans' },
      { status: 500 }
    );
  }
}
```

レスポンス型:
```typescript
interface PlansApiResponse {
  projects: ProjectConfig[];
  plans: PlanFile[];
}
```

## 検証
```bash
cd dashboard && npm run dev
curl http://localhost:3000/api/plans | jq .
```
JSON レスポンスにプロジェクト一覧と PLAN データが含まれることを確認。
